Create a new component that renders a single channel binding card showing the channel name, status, session strategy, and hover actions.

**New file:** `apps/client/src/layers/features/agent-settings/ui/ChannelBindingCard.tsx`

**FSD layer:** `features/agent-settings` — can import from `entities/` and `shared/`.

**Props interface:**
```typescript
import type { AdapterBinding } from '@dorkos/shared/relay-schemas';

interface ChannelBindingCardProps {
  /** The binding to display. */
  binding: AdapterBinding;
  /** Display name of the channel (adapter displayName from catalog). */
  channelName: string;
  /** Current adapter connection state. */
  adapterState: 'connected' | 'disconnected' | 'error';
  /** Whether the adapter has an error message to show. */
  errorMessage?: string;
  /** Called when the user clicks Edit. */
  onEdit: () => void;
  /** Called when the user confirms removal. */
  onRemove: () => void;
}
```

**Component structure:**
```tsx
export function ChannelBindingCard({
  binding,
  channelName,
  adapterState,
  errorMessage,
  onEdit,
  onRemove,
}: ChannelBindingCardProps) {
  const [showRemoveConfirm, setShowRemoveConfirm] = useState(false);

  return (
    <div
      className={cn(
        'group relative rounded-lg border px-3 py-2.5 transition-colors',
        adapterState === 'error' && 'border-red-500/50'
      )}
    >
      <div className="flex items-center gap-3">
        {/* Status dot */}
        <span
          className={cn(
            'size-2 shrink-0 rounded-full',
            adapterState === 'connected' && 'bg-green-500',
            adapterState === 'disconnected' && 'bg-amber-500',
            adapterState === 'error' && 'bg-red-500'
          )}
        />

        {/* Channel name */}
        <span className="text-sm font-medium">{channelName}</span>

        {/* Strategy badge */}
        <Badge variant="outline" className="text-xs">
          {binding.sessionStrategy}
        </Badge>

        {/* Chat filter badge (optional) */}
        {binding.chatId && (
          <Badge variant="secondary" className="text-xs">
            {binding.chatId}
          </Badge>
        )}

        {/* Permission icons */}
        <div className="ml-auto flex items-center gap-1">
          {binding.canInitiate && (
            <Tooltip><TooltipTrigger><Zap className="text-muted-foreground size-3" /></TooltipTrigger>
              <TooltipContent>Can initiate conversations</TooltipContent></Tooltip>
          )}
          {!binding.canReply && (
            <Tooltip><TooltipTrigger><MessageSquareOff className="text-muted-foreground/50 size-3" /></TooltipTrigger>
              <TooltipContent>Cannot reply</TooltipContent></Tooltip>
          )}
          {!binding.canReceive && (
            <Tooltip><TooltipTrigger><BellOff className="text-muted-foreground/50 size-3" /></TooltipTrigger>
              <TooltipContent>Cannot receive</TooltipContent></Tooltip>
          )}
        </div>

        {/* Hover actions */}
        <div className="flex items-center gap-1 opacity-0 transition-opacity group-hover:opacity-100">
          <Button variant="ghost" size="sm" className="h-7 px-2 text-xs" onClick={onEdit}>
            Edit
          </Button>
          <Button
            variant="ghost"
            size="sm"
            className="text-destructive h-7 px-2 text-xs"
            onClick={() => setShowRemoveConfirm(true)}
          >
            Remove
          </Button>
        </div>
      </div>

      {/* Error detail */}
      {adapterState === 'error' && errorMessage && (
        <p className="mt-1.5 text-xs text-red-500">{errorMessage}</p>
      )}

      {/* Remove confirmation */}
      <AlertDialog open={showRemoveConfirm} onOpenChange={setShowRemoveConfirm}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Remove channel binding</AlertDialogTitle>
            <AlertDialogDescription>
              Remove the binding to {channelName}? The agent will no longer receive messages from this channel.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => { onRemove(); setShowRemoveConfirm(false); }}
              className="bg-red-600 hover:bg-red-700"
            >
              Remove
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}
```

**Imports needed:**
- `useState` from `react`
- `Zap`, `MessageSquareOff`, `BellOff` from `lucide-react`
- `Badge`, `Button`, `Tooltip`, `TooltipTrigger`, `TooltipContent`, `AlertDialog`, `AlertDialogContent`, `AlertDialogHeader`, `AlertDialogTitle`, `AlertDialogDescription`, `AlertDialogFooter`, `AlertDialogCancel`, `AlertDialogAction` from `@/layers/shared/ui`
- `cn` from `@/layers/shared/lib`
- `AdapterBinding` type from `@dorkos/shared/relay-schemas`

**Acceptance criteria:**
- Card shows status dot, channel name, strategy badge, chat filter badge, permission icons
- Hover reveals Edit and Remove buttons
- Remove button shows confirmation dialog before calling onRemove
- Error state shows red border and error message
- Component renders correctly in isolation (test with mock binding data)

Create a popover component that lists available configured channels for binding to an agent, with a footer to navigate to Settings for new channel setup.

**New file:** `apps/client/src/layers/features/agent-settings/ui/ChannelPicker.tsx`

**FSD layer:** `features/agent-settings` — can import from `entities/` and `shared/`.

**Props interface:**
```typescript
interface ChannelPickerProps {
  /** Called when the user selects a channel to bind. Receives the adapter instance ID. */
  onSelectChannel: (adapterId: string) => void;
  /** Called when the user clicks "Set up a new channel" to navigate to Settings. */
  onSetupNewChannel: () => void;
  /** Adapter IDs already bound to this agent (to show as "already connected"). */
  boundAdapterIds: Set<string>;
  /** Whether the popover trigger button is disabled. */
  disabled?: boolean;
}
```

**Component implementation:**
```tsx
import { Plus } from 'lucide-react';
import { Popover, PopoverContent, PopoverTrigger, Button } from '@/layers/shared/ui';
import { cn } from '@/layers/shared/lib';
import { useAdapterCatalog } from '@/layers/entities/relay';
import { useRelayEnabled } from '@/layers/entities/relay';

export function ChannelPicker({
  onSelectChannel,
  onSetupNewChannel,
  boundAdapterIds,
  disabled,
}: ChannelPickerProps) {
  const relayEnabled = useRelayEnabled();
  const { data: catalog = [] } = useAdapterCatalog(relayEnabled);
  const [open, setOpen] = useState(false);

  // Flatten catalog to individual configured instances
  const configuredChannels = catalog.flatMap((entry) =>
    entry.instances.map((inst) => ({
      id: inst.id,
      displayName: inst.displayName ?? entry.manifest.displayName,
      label: inst.label,
      state: inst.status?.state ?? 'disconnected',
      disabled: inst.status?.state === 'error' || inst.enabled === false,
      alreadyBound: boundAdapterIds.has(inst.id),
    }))
  );

  function handleSelect(adapterId: string) {
    onSelectChannel(adapterId);
    setOpen(false);
  }

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button variant="outline" size="sm" disabled={disabled}>
          <Plus className="mr-1.5 size-3.5" />
          Connect to Channel
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-72 p-0" align="start">
        <div className="max-h-64 overflow-y-auto">
          {configuredChannels.length === 0 ? (
            <div className="px-3 py-4 text-center">
              <p className="text-muted-foreground text-sm">No channels configured</p>
            </div>
          ) : (
            <div className="py-1">
              {configuredChannels.map((channel) => (
                <button
                  key={channel.id}
                  disabled={channel.disabled || channel.alreadyBound}
                  onClick={() => handleSelect(channel.id)}
                  className={cn(
                    'flex w-full items-center gap-3 px-3 py-2 text-left text-sm transition-colors',
                    'hover:bg-accent disabled:opacity-50 disabled:cursor-not-allowed'
                  )}
                >
                  <span
                    className={cn(
                      'size-2 shrink-0 rounded-full',
                      channel.state === 'connected' && 'bg-green-500',
                      channel.state === 'disconnected' && 'bg-amber-500',
                      channel.state === 'error' && 'bg-red-500'
                    )}
                  />
                  <div className="flex-1 min-w-0">
                    <p className="truncate font-medium">{channel.displayName}</p>
                    {channel.label && (
                      <p className="text-muted-foreground truncate text-xs">{channel.label}</p>
                    )}
                  </div>
                  <span className="text-muted-foreground/60 text-xs">
                    {channel.alreadyBound ? 'connected' : channel.state}
                  </span>
                </button>
              ))}
            </div>
          )}
        </div>
        {/* Footer: set up new channel */}
        <div className="border-t px-3 py-2">
          <button
            onClick={() => {
              setOpen(false);
              onSetupNewChannel();
            }}
            className="text-muted-foreground hover:text-foreground flex w-full items-center gap-2 text-left text-xs transition-colors"
          >
            <Plus className="size-3" />
            Set up a new channel...
          </button>
        </div>
      </PopoverContent>
    </Popover>
  );
}
```

**Acceptance criteria:**
- Popover lists all configured adapter instances with status dot, name, label, and state text
- Disabled/error channels are shown but not clickable
- Already-bound channels shown as "connected" and disabled
- Selecting a channel calls `onSelectChannel` with the adapter instance ID and closes the popover
- Footer "Set up a new channel..." calls `onSetupNewChannel` and closes the popover
- Empty state shows "No channels configured" when no adapters exist
- Popover is lazily rendered (only mounts when open)

Create the new ChannelsTab component that replaces the old ConnectionsTab in the Agent Dialog, providing inline binding management with ChannelBindingCard and ChannelPicker.

**New file:** `apps/client/src/layers/features/agent-settings/ui/ChannelsTab.tsx`

**FSD layer:** `features/agent-settings` — can import from `entities/` and `shared/`, and can render sibling feature UI components (BindingDialog from `features/mesh`).

**Props interface:**
```typescript
import type { AgentManifest } from '@dorkos/shared/mesh-schemas';

interface ChannelsTabProps {
  agent: AgentManifest;
}
```

**Full component implementation:**
```tsx
import { useState, useMemo, useCallback } from 'react';
import { Radio } from 'lucide-react';
import { toast } from 'sonner';
import type { AgentManifest } from '@dorkos/shared/mesh-schemas';
import type { AdapterBinding } from '@dorkos/shared/relay-schemas';
import { useBindings, useCreateBinding, useDeleteBinding } from '@/layers/entities/binding';
import { useAdapterCatalog, useRelayEnabled } from '@/layers/entities/relay';
import { useMeshAgentHealth } from '@/layers/entities/mesh';
import { useAppStore } from '@/layers/shared/model';
import { Button } from '@/layers/shared/ui';
import { BindingDialog, type BindingFormValues } from '@/layers/features/mesh/ui/BindingDialog';
import { ChannelBindingCard } from './ChannelBindingCard';
import { ChannelPicker } from './ChannelPicker';
import { SubsystemRow } from './SubsystemRow';

interface ChannelsTabProps {
  agent: AgentManifest;
}

export function ChannelsTab({ agent }: ChannelsTabProps) {
  const relayEnabled = useRelayEnabled();
  const { data: bindings = [] } = useBindings();
  const { data: catalog = [] } = useAdapterCatalog(relayEnabled);
  const { data: health } = useMeshAgentHealth(agent.id);
  const createBinding = useCreateBinding();
  const deleteBinding = useDeleteBinding();
  const { setAgentDialogOpen, openSettingsToTab } = useAppStore();
  const [editBinding, setEditBinding] = useState<AdapterBinding | null>(null);

  // Filter bindings for this agent
  const agentBindings = useMemo(
    () => bindings.filter((b) => b.agentId === agent.id),
    [bindings, agent.id]
  );

  // Build a lookup from adapterId to catalog info
  const adapterLookup = useMemo(() => {
    const map = new Map<string, { displayName: string; state: string; errorMessage?: string }>();
    for (const entry of catalog) {
      for (const inst of entry.instances) {
        map.set(inst.id, {
          displayName: inst.displayName ?? entry.manifest.displayName,
          state: inst.status?.state ?? 'disconnected',
          errorMessage: inst.status?.error,
        });
      }
    }
    return map;
  }, [catalog]);

  const boundAdapterIds = useMemo(
    () => new Set(agentBindings.map((b) => b.adapterId)),
    [agentBindings]
  );

  const hasConfiguredChannels = catalog.some((e) => e.instances.length > 0);

  const handleSelectChannel = useCallback(
    async (adapterId: string) => {
      try {
        await createBinding.mutateAsync({
          adapterId,
          agentId: agent.id,
          sessionStrategy: 'per-chat',
          canInitiate: true,
          canReply: true,
          canReceive: true,
        });
        toast.success('Channel connected');
      } catch (err) {
        toast.error(err instanceof Error ? err.message : 'Failed to connect channel');
      }
    },
    [agent.id, createBinding]
  );

  const handleRemoveBinding = useCallback(
    async (bindingId: string) => {
      try {
        await deleteBinding.mutateAsync(bindingId);
        toast.success('Channel disconnected');
      } catch (err) {
        toast.error(err instanceof Error ? err.message : 'Failed to disconnect channel');
      }
    },
    [deleteBinding]
  );

  const handleSetupNewChannel = useCallback(() => {
    setAgentDialogOpen(false);
    requestAnimationFrame(() => openSettingsToTab('channels'));
  }, [setAgentDialogOpen, openSettingsToTab]);

  return (
    <div className="space-y-6">
      {/* Channel Bindings Section */}
      <section className="space-y-3">
        {agentBindings.length > 0 ? (
          <>
            <div className="space-y-2">
              {agentBindings.map((binding) => {
                const info = adapterLookup.get(binding.adapterId);
                return (
                  <ChannelBindingCard
                    key={binding.id}
                    binding={binding}
                    channelName={info?.displayName ?? 'Unknown channel'}
                    adapterState={(info?.state as 'connected' | 'disconnected' | 'error') ?? 'disconnected'}
                    errorMessage={info?.errorMessage}
                    onEdit={() => setEditBinding(binding)}
                    onRemove={() => handleRemoveBinding(binding.id)}
                  />
                );
              })}
            </div>
            <ChannelPicker
              onSelectChannel={handleSelectChannel}
              onSetupNewChannel={handleSetupNewChannel}
              boundAdapterIds={boundAdapterIds}
            />
          </>
        ) : hasConfiguredChannels ? (
          /* Empty: no bindings but channels exist */
          <div className="flex flex-col items-center gap-3 rounded-xl border border-dashed py-8">
            <Radio className="text-muted-foreground/40 size-8" />
            <div className="text-center">
              <p className="text-muted-foreground text-sm">No channels connected</p>
              <p className="text-muted-foreground/60 text-xs">
                Connect a channel to make this agent reachable externally
              </p>
            </div>
            <ChannelPicker
              onSelectChannel={handleSelectChannel}
              onSetupNewChannel={handleSetupNewChannel}
              boundAdapterIds={boundAdapterIds}
            />
          </div>
        ) : (
          /* Empty: no channels configured system-wide */
          <div className="flex flex-col items-center gap-3 rounded-xl border border-dashed py-8">
            <Radio className="text-muted-foreground/40 size-8" />
            <div className="text-center">
              <p className="text-muted-foreground text-sm">No channels configured</p>
              <p className="text-muted-foreground/60 text-xs">
                Set up a channel in Settings to connect agents to external platforms
              </p>
            </div>
            <Button onClick={handleSetupNewChannel}>Set Up a Channel</Button>
          </div>
        )}
      </section>

      {/* Mesh Health Footer */}
      <SubsystemRow
        label="Mesh Health"
        enabled={true}
        status={
          health
            ? { state: health.status, lastSeenAt: health.lastSeenAt }
            : undefined
        }
        loading={!health}
      />

      {/* Edit Binding Dialog */}
      {editBinding && (
        <BindingDialog
          open
          onOpenChange={(open) => { if (!open) setEditBinding(null); }}
          mode="edit"
          initialValues={{
            adapterId: editBinding.adapterId,
            agentId: editBinding.agentId,
            sessionStrategy: editBinding.sessionStrategy,
            label: editBinding.label ?? '',
            permissionMode: editBinding.permissionMode,
            chatId: editBinding.chatId,
            channelType: editBinding.channelType,
            canInitiate: editBinding.canInitiate,
            canReply: editBinding.canReply,
            canReceive: editBinding.canReceive,
          }}
          adapterName={adapterLookup.get(editBinding.adapterId)?.displayName}
          onConfirm={async (values) => {
            // handled by existing BindingDialog update flow
          }}
          onDelete={async (id) => {
            await handleRemoveBinding(id);
            setEditBinding(null);
          }}
          bindingId={editBinding.id}
          isPending={false}
        />
      )}
    </div>
  );
}
```

