Create the Channels tab for the Settings dialog that shows active channels and available channel types from the catalog.

**New file:** `apps/client/src/layers/features/settings/ui/ChannelsTab.tsx`

**FSD layer:** `features/settings` — can import from `entities/` and `shared/`, and can render sibling feature UI components.

**Full component implementation:**
```tsx
import { useState, useMemo } from 'react';
import { Radio } from 'lucide-react';
import { useAdapterCatalog, useRelayEnabled, useToggleAdapter, useRemoveAdapter } from '@/layers/entities/relay';
import { useBindings } from '@/layers/entities/binding';
import { FieldCard, FieldCardContent, FeatureDisabledState } from '@/layers/shared/ui';
import type { AdapterManifest } from '@dorkos/shared/relay-schemas';
import { CatalogCard } from '@/layers/features/relay/ui/CatalogCard';
import { AdapterSetupWizard } from '@/layers/features/relay/ui/AdapterSetupWizard';
import { ChannelSettingRow } from './ChannelSettingRow';

interface WizardState {
  open: boolean;
  manifest?: AdapterManifest;
  instanceId?: string;
}

/** System-level channel management within the Settings dialog. */
export function ChannelsTab() {
  const relayEnabled = useRelayEnabled();
  const { data: catalog = [] } = useAdapterCatalog(relayEnabled);
  const { data: bindings = [] } = useBindings();
  const { mutate: toggleAdapter } = useToggleAdapter();
  const { mutate: removeAdapter } = useRemoveAdapter();
  const [wizardState, setWizardState] = useState<WizardState>({ open: false });

  // Count bindings per adapter
  const agentCountByAdapter = useMemo(() => {
    const counts = new Map<string, number>();
    for (const b of bindings) {
      counts.set(b.adapterId, (counts.get(b.adapterId) ?? 0) + 1);
    }
    return counts;
  }, [bindings]);

  if (!relayEnabled) {
    return (
      <FeatureDisabledState
        icon={Radio}
        name="Channels"
        description="Channels require Relay. Start DorkOS with relay enabled."
        command="DORKOS_RELAY_ENABLED=true dorkos"
      />
    );
  }

  // Configured instances
  const configuredChannels = catalog.flatMap((entry) =>
    entry.instances.map((inst) => ({
      instance: inst,
      manifest: entry.manifest,
    }))
  );

  // Available catalog entries (not yet configured, or multi-instance)
  const availableEntries = catalog.filter(
    (entry) =>
      !entry.manifest.deprecated &&
      (entry.instances.length === 0 || entry.manifest.multiInstance)
  );

  const openWizardForAdd = (manifest: AdapterManifest) => {
    setWizardState({ open: true, manifest });
  };

  const openWizardForConfigure = (manifest: AdapterManifest, instanceId: string) => {
    setWizardState({ open: true, manifest, instanceId });
  };

  const existingInstance = wizardState.instanceId
    ? catalog.flatMap((e) => e.instances).find((inst) => inst.id === wizardState.instanceId)
    : undefined;

  return (
    <div className="space-y-6">
      {/* Active Channels */}
      <section>
        <h3 className="text-muted-foreground mb-2 text-xs font-semibold tracking-wide uppercase">
          Active Channels
        </h3>
        {configuredChannels.length === 0 ? (
          <div className="flex flex-col items-center gap-3 rounded-xl border border-dashed py-8">
            <Radio className="text-muted-foreground/40 size-8" />
            <p className="text-muted-foreground text-sm">No channels configured</p>
            <p className="text-muted-foreground/60 text-xs">
              Add a channel from the catalog below
            </p>
          </div>
        ) : (
          <FieldCard>
            <FieldCardContent>
              {configuredChannels.map(({ instance, manifest }) => (
                <ChannelSettingRow
                  key={instance.id}
                  instanceId={instance.id}
                  displayName={instance.displayName ?? manifest.displayName}
                  label={instance.label}
                  state={(instance.status?.state as 'connected' | 'disconnected' | 'error') ?? 'disconnected'}
                  enabled={instance.enabled !== false}
                  agentCount={agentCountByAdapter.get(instance.id) ?? 0}
                  onToggle={(enabled) => toggleAdapter({ id: instance.id, enabled })}
                  onConfigure={() => openWizardForConfigure(manifest, instance.id)}
                />
              ))}
            </FieldCardContent>
          </FieldCard>
        )}
      </section>

      {/* Available Channels */}
      <section>
        <h3 className="text-muted-foreground mb-2 text-xs font-semibold tracking-wide uppercase">
          Available Channels
        </h3>
        {availableEntries.length === 0 ? (
          <p className="text-muted-foreground text-sm">
            All channel types are configured.
          </p>
        ) : (
          <div
            className="grid gap-2"
            style={{ gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))' }}
          >
            {availableEntries.map((entry) => (
              <CatalogCard
                key={entry.manifest.type}
                manifest={entry.manifest}
                onAdd={() => openWizardForAdd(entry.manifest)}
              />
            ))}
          </div>
        )}
      </section>

      {/* Setup Wizard */}
      {wizardState.manifest && (
        <AdapterSetupWizard
          open={wizardState.open}
          onOpenChange={(open) => {
            if (!open) setWizardState({ open: false });
          }}
          manifest={wizardState.manifest}
          existingInstance={existingInstance}
          existingAdapterIds={catalog.flatMap((e) => e.instances.map((i) => i.id))}
        />
      )}
    </div>
  );
}
```

